**`auth.setup.ts`** only covers the happy path. Untested:

```typescript
// tests/frontend/e2e/test_auth_edge_cases.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Auth Edge Cases', () => {
  test('zeigt deutschen Fehlertext bei falschen Anmeldedaten', async ({ page }) => {
    await page.goto('/login');
    await page.locator('input[type="email"]').fill('falsch@example.com');
    await page.locator('input[type="password"]').fill('falschesPasswort');
    await page.locator('button[type="submit"]').click();

    // Must verify exact German error copy, not just "some error exists"
    const error = page.locator('[role="alert"], .error-message');
    await expect(error).toBeVisible({ timeout: 5000 });
    await expect(error).toContainText(/ungültige|Anmeldung fehlgeschlagen|falsches Passwort/i);
    await expect(page).toHaveURL(/\/login/);  // stays on login page
  });

  test('sperrt Konto nach 5 fehlgeschlagenen Versuchen (Rate Limit)', async ({ page }) => {
    await page.goto('/login');
    for (let i = 0; i < 5; i++) {
      await page.locator('input[type="email"]').fill('target@example.com');
      await page.locator('input[type="password"]').fill(`falsch${i}`);
      await page.locator('button[type="submit"]').click();
      await page.waitForTimeout(300);
    }
    const lockoutMessage = page.locator('[role="alert"]');
    await expect(lockoutMessage).toContainText(/gesperrt|zu viele Versuche|429/i);
  });

  test('leitet nach Ablauf des Tokens zur Login-Seite weiter', async ({ page }) => {
    await page.goto('/');
    // Simulate expired token
    await page.evaluate(() => localStorage.setItem('access_token', 'expired.token.here'));
    await page.reload();

    // Should redirect to login
    await page.waitForURL(/\/login/, { timeout: 10000 });
    await expect(page).toHaveURL(/\/login/);
  });

  test('erneuert Token automatisch mit Refresh Token', async ({ page, request }) => {
    // Set expired access but valid refresh token
    await page.goto('/');
    await page.evaluate(() => {
      localStorage.setItem('access_token', 'expired.token');
      // refresh_token is still valid (set in setup)
    });

    // Navigate to protected resource
    await page.goto('/documents');

    // Should NOT redirect to login — refresh should happen silently
    await page.waitForLoadState('networkidle');
    await expect(page).not.toHaveURL(/\/login/);
  });

  test('2FA-Flow: zeigt TOTP-Eingabe nach erstem Login-Schritt', async ({ page }) => {
    // Requires a test user with 2FA enabled
    await page.goto('/login');
    await page.locator('input[type="email"]').fill(process.env.TEST_2FA_USER || '2fa@test.local');
    await page.locator('input[type="password"]').fill(process.env.TEST_2FA_PASS || 'Test123!');
    await page.locator('button[type="submit"]').click();

    const totpInput = page.locator('input[name="totp"], input[placeholder*="Code"], input[maxlength="6"]');
    await expect(totpInput).toBeVisible({ timeout: 5000 });
  });

  test('Abmelden löscht Session und leitet zu Login weiter', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    const logoutButton = page.locator('button:has-text("Abmelden"), a:has-text("Abmelden")');
    if (await logoutButton.isVisible({ timeout: 3000 }).catch(() => false)) {
      await logoutButton.click();
      await page.waitForURL(/\/login/, { timeout: 5000 });

      // Token should be cleared
      const token = await page.evaluate(() => localStorage.getItem('access_token'));
      expect(token).toBeNull();
    }
  });
});
