The document workflow tests only test read. There are no tests for the full CRUD lifecycle:

```typescript
// tests/frontend/e2e/test_document_crud.spec.ts
import { test, expect } from '@playwright/test';
import path from 'path';
import { createTestPdfBuffer } from './utils/fixtures';
import { waitForToast, waitForDialog, confirmDialog } from './utils/helpers';

test.use({ storageState: path.join(__dirname, '.auth', 'user.json') });

test.describe('Document CRUD', () => {
  let uploadedDocumentId: string;

  test('Upload: PDF wird hochgeladen und erhält ID', async ({ page }) => {
    const uploadResponse = page.waitForResponse(
      (r) => r.url().includes('/api/v1/documents') && r.request().method() === 'POST'
    );

    await page.goto('/upload');
    await page.waitForLoadState('domcontentloaded');

    const fileInput = page.locator('input[type="file"]');
    await fileInput.setInputFiles({
      name: 'test_rechnung.pdf',
      mimeType: 'application/pdf',
      buffer: createTestPdfBuffer(),
    });

    const response = await uploadResponse;
    expect(response.status()).toBe(201);
    const body = await response.json();
    expect(body).toHaveProperty('id');
    uploadedDocumentId = body.id;

    await waitForToast(page, /hochgeladen|erfolgreich/i);
  });

  test('Upload: Abgelehnte Dateitypen zeigen deutschen Fehler', async ({ page }) => {
    await page.goto('/upload');

    const fileInput = page.locator('input[type="file"]');
    await fileInput.setInputFiles({
      name: 'malware.exe',
      mimeType: 'application/octet-stream',
      buffer: Buffer.from('MZ executable'),
    });

    const error = page.locator('[role="alert"], .error-message, .text-destructive');
    await expect(error).toBeVisible({ timeout: 3000 });
    await expect(error).toContainText(/ungültiges|nicht unterstützt|Format/i);
  });

  test('Upload: Datei > 50MB zeigt Fehlermeldung', async ({ page }) => {
    await page.goto('/upload');

    // Create a buffer that exceeds the limit
    const largePdf = Buffer.alloc(51 * 1024 * 1024, 0);
    const fileInput = page.locator('input[type="file"]');
    await fileInput.setInputFiles({
      name: 'zu_gross.pdf',
      mimeType: 'application/pdf',
      buffer: largePdf,
    });

    const error = page.locator('[role="alert"], .text-destructive');
    await expect(error).toContainText(/zu groß|Datei zu groß/i);
  });

  test('Detail: Hochgeladenes Dokument ist in der Liste sichtbar', async ({ page }) => {
    test.skip(!uploadedDocumentId, 'Setzt erfolgreichen Upload-Test voraus');

    await page.goto('/documents');
    await page.waitForLoadState('networkidle');

    const documentRow = page.locator(`[data-id="${uploadedDocumentId}"], tr:has-text("test_rechnung")`);
    await expect(documentRow).toBeVisible({ timeout: 10000 });
  });

  test('Edit: Dokumententitel kann bearbeitet werden', async ({ page }) => {
    test.skip(!uploadedDocumentId, 'Setzt erfolgreichen Upload-Test voraus');

    await page.goto(`/documents/${uploadedDocumentId}`);
    await page.waitForLoadState('networkidle');

    const editButton = page.locator('button:has-text("Bearbeiten"), [aria-label*="bearbeiten"]').first();
    await editButton.click();

    const titleInput = page.locator('input[name="title"], input[placeholder*="Titel"]').first();
    await titleInput.fill('Aktualisierter Titel');
    await page.keyboard.press('Enter');

    await waitForToast(page, /gespeichert|aktualisiert/i);
    await expect(page.locator('h1, [data-testid="document-title"]')).toContainText('Aktualisierter Titel');
  });

  test('Delete: Dokument löschen mit Bestätigungsdialog', async ({ page }) => {
    test.skip(!uploadedDocumentId, 'Setzt erfolgreichen Upload-Test voraus');

    await page.goto(`/documents/${uploadedDocumentId}`);
    await page.waitForLoadState('networkidle');

    const deleteButton = page.locator('button:has-text("Löschen"), [aria-label*="löschen"]').first();
    await deleteButton.click();

    // Must show confirmation dialog — no silent deletes
    const dialog = await waitForDialog(page);
    await expect(dialog).toContainText(/löschen|entfernen/i);
    await confirmDialog(page);

    await waitForToast(page, /gelöscht/i);

    // Document should no longer be accessible
    const response = await page.request.get(`/api/v1/documents/${uploadedDocumentId}`);
    expect(response.status()).toBe(404);
  });

  test('Delete: Abbrechen lässt Dokument bestehen', async ({ page }) => {
    test.skip(!uploadedDocumentId, 'Setzt erfolgreichen Upload-Test voraus');

    await page.goto(`/documents/${uploadedDocumentId}`);
    const deleteButton = page.locator('button:has-text("Löschen")').first();
    await deleteButton.click();

    const dialog = await waitForDialog(page);
    const cancelButton = dialog.locator('button:has-text("Abbrechen")');
    await cancelButton.click();

    // Document still exists
    const response = await page.request.get(`/api/v1/documents/${uploadedDocumentId}`);
    expect(response.status()).toBe(200);
  });
});
