No tests verify that API errors produce German-language user-facing messages. This violates CLAUDE.md Rule #2:

```typescript
// tests/frontend/e2e/test_api_error_states.spec.ts
import { test, expect } from '@playwright/test';
import path from 'path';

test.use({ storageState: path.join(__dirname, '.auth', 'user.json') });

test.describe('API Fehlerbehandlung (Deutsche Fehlermeldungen)', () => {
  test('401 Unauthorized: Zeigt deutschen Hinweis', async ({ page }) => {
    await page.route('**/api/v1/documents*', (route) =>
      route.fulfill({ status: 401, body: JSON.stringify({ detail: 'Unauthorized' }) })
    );

    await page.goto('/documents');
    await page.waitForLoadState('networkidle');

    const errorText = await page.locator('body').textContent();
    // Must NOT show raw "Unauthorized" or "401" — must be localized
    expect(errorText).not.toContain('Unauthorized');
    const hasGermanError = /Sitzung abgelaufen|Nicht angemeldet|Bitte melden/i.test(errorText || '');
    expect(hasGermanError).toBeTruthy();
  });

  test('403 Forbidden: Zeigt deutschen Zugriffsverweigert-Text', async ({ page }) => {
    await page.route('**/api/v1/admin/**', (route) =>
      route.fulfill({ status: 403, body: JSON.stringify({ detail: 'Forbidden' }) })
    );

    await page.goto('/admin');
    await page.waitForLoadState('networkidle');

    const errorText = await page.locator('body').textContent();
    expect(errorText).not.toContain('Forbidden');
    const hasGermanError = /Zugriff verweigert|keine Berechtigung|nicht erlaubt/i.test(errorText || '');
    expect(hasGermanError).toBeTruthy();
  });

  test('404 Not Found: Zeigt deutsche 404-Seite', async ({ page }) => {
    await page.goto('/diese-seite-existiert-nicht-xyz123');
    await page.waitForLoadState('networkidle');

    const bodyText = await page.locator('body').textContent();
    expect(bodyText).not.toContain('404 Not Found'); // raw HTTP text
    expect(
      /nicht gefunden|Seite existiert nicht|Seite wurde nicht gefunden/i.test(bodyText || '')
    ).toBeTruthy();
  });

  test('500 Server Error: Zeigt deutschen Fehlerdialog, kein Stack Trace', async ({ page }) => {
    await page.route('**/api/v1/documents*', (route) =>
      route.fulfill({
        status: 500,
        body: JSON.stringify({ detail: 'Internal Server Error', traceback: 'File "/app/main.py"...' }),
      })
    );

    await page.goto('/documents');
    await page.waitForLoadState('networkidle');

    const bodyText = await page.locator('body').textContent();
    // Must not leak stack trace to user
    expect(bodyText).not.toContain('traceback');
    expect(bodyText).not.toContain('File "/app');
    // Must show user-friendly German message
    expect(
      /Fehler aufgetreten|Server.*Fehler|versuchen Sie es erneut/i.test(bodyText || '')
    ).toBeTruthy();
  });

  test('Network Timeout: Zeigt deutschen Hinweis bei Zeitüberschreitung', async ({ page }) => {
    await page.route('**/api/v1/documents*', (route) => route.abort('timedout'));

    await page.goto('/documents');
    await page.waitForLoadState('domcontentloaded');
    await page.waitForTimeout(3000);

    const bodyText = await page.locator('body').textContent();
    const hasTimeoutMessage = /Zeitüberschreitung|keine Verbindung|Verbindung fehlgeschlagen/i.test(
      bodyText || ''
    );
    // Either a German timeout message or a retry button
    const hasRetryButton = await page.locator('button:has-text("Erneut versuchen")').isVisible({ timeout: 1000 }).catch(() => false);
    expect(hasTimeoutMessage || hasRetryButton).toBeTruthy();
  });
});
