The `Multi-Tenancy-Security.md` doc is listed but no E2E tests cover tenant isolation:

```typescript
// tests/frontend/e2e/test_access_control.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Zugriffskontrolle (RBAC)', () => {
  test('Admin-Bereich ist für normale Benutzer nicht zugänglich', async ({ page, request }) => {
    // Use non-admin auth state
    // This test requires a second auth state file for a regular user
    const response = await request.get('/api/v1/admin/users');
    // Regular users should get 403
    expect([401, 403]).toContain(response.status());
  });

  test('Dokumente anderer Mandanten sind nicht zugänglich', async ({ request }) => {
    // Try to access a document ID from another tenant (known invalid cross-tenant ID)
    const response = await request.get('/api/v1/documents/00000000-0000-0000-0000-000000000001');
    expect([403, 404]).toContain(response.status());
  });

  test('API-Keys: Scope-Beschränkungen werden durchgesetzt', async ({ request }) => {
    // Test that a read-only API key cannot perform writes
    const readOnlyKey = process.env.TEST_READONLY_API_KEY;
    if (!readOnlyKey) test.skip();

    const response = await request.post('/api/v1/documents', {
      headers: { Authorization: `Bearer ${readOnlyKey}` },
      data: { title: 'Should fail' },
    });
    expect(response.status()).toBe(403);
  });
});
