The invoice tests navigate to the page but never exercise the actual business logic. The `skonto_service.py` calculates deadlines and savings — none of that is verified:

```typescript
// tests/frontend/e2e/test_skonto_workflow.spec.ts
import { test, expect } from '@playwright/test';
import path from 'path';

test.use({ storageState: path.join(__dirname, '.auth', 'user.json') });

test.describe('Skonto-Workflow', () => {
  test('Skonto-Fristwarnung erscheint X Tage vor Ablauf', async ({ page, request }) => {
    // Create invoice with 14-day skonto via API
    const invoice = await request.post('/api/v1/invoices', {
      data: {
        amount: 1000,
        skonto_percent: 2.0,
        skonto_days: 14,
        due_date: new Date(Date.now() + 3 * 86400_000).toISOString().split('T')[0],
      },
    });
    if (invoice.status() !== 201) test.skip();
    const { id } = await invoice.json();

    await page.goto('/admin/banking/skonto');
    await page.waitForLoadState('networkidle');

    // Should show this invoice as urgent (3 days left)
    const urgentRow = page.locator(`[data-invoice-id="${id}"], tr:has-text("${id}")`);
    if (await urgentRow.isVisible({ timeout: 5000 }).catch(() => false)) {
      await expect(urgentRow).toHaveClass(/urgent|warning|danger/);
    }
  });

  test('Skonto-Betrag wird korrekt berechnet (2% von 1000€ = 20€)', async ({ page }) => {
    await page.goto('/admin/banking/skonto');
    await page.waitForLoadState('networkidle');

    // Find any row showing skonto calculation
    const skontoAmounts = page.locator('[data-testid*="skonto-amount"], td:has-text("€")');
    const count = await skontoAmounts.count();

    if (count > 0) {
      const firstAmount = await skontoAmounts.first().textContent();
      // Verify it's a valid EUR amount, not NaN
      expect(firstAmount).toMatch(/\d+[.,]\d{2}\s*€|€\s*\d+[.,]\d{2}/);
      expect(firstAmount).not.toContain('NaN');
      expect(firstAmount).not.toContain('undefined');
    }
  });

  test('Teilzahlung: Reduziert offenen Betrag korrekt', async ({ page, request }) => {
    const invoice = await request.post('/api/v1/invoices', {
      data: { amount: 500, due_date: new Date(Date.now() + 30 * 86400_000).toISOString().split('T')[0] },
    });
    if (invoice.status() !== 201) test.skip();
    const { id } = await invoice.json();

    // Record partial payment of 200
    const payment = await request.post(`/api/v1/invoices/${id}/payments`, {
      data: { amount: 200 },
    });
    expect(payment.status()).toBe(201);

    await page.goto(`/admin/banking/transactions`);
    await page.waitForLoadState('networkidle');

    // Remaining balance should be 300, not 500
    const balanceElement = page.locator(`[data-invoice-id="${id}"] [data-testid="balance"]`);
    if (await balanceElement.isVisible({ timeout: 3000 }).catch(() => false)) {
      const balance = await balanceElement.textContent();
      expect(balance).toContain('300');
    }
  });
});
